import { chromium } from 'playwright';
import { readFileSync } from 'fs';
import { fileURLToPath } from 'url';
import path from 'path';

const cookiesPath = 'C:\\Users\\yyzypublic\\.openclaw\\workspace\\devops_cookies.json';
const targetUrl = 'https://devops.devcloud.ztgame.com/projects/yyzy/pipelines/p-f78c977835c84b71a6d58b4746cd1c4a';

async function run() {
  const browser = await chromium.launch({ headless: true });
  const context = await browser.newContext();

  // Load cookies
  const cookiesRaw = readFileSync(cookiesPath, 'utf-8');
  const cookies = JSON.parse(cookiesRaw);
  await context.addCookies(cookies);

  const page = await context.newPage();

  console.log('Navigating to pipeline page...');
  await page.goto(targetUrl, { waitUntil: 'networkidle', timeout: 30000 });

  // Take screenshot to see current state
  await page.screenshot({ path: 'C:\\Users\\yyzypublic\\.openclaw\\workspace\\qa_build_01_loaded.png', fullPage: false });
  console.log('Page loaded, screenshot taken');

  // Check if we're on the right page or need to login
  const pageTitle = await page.title();
  console.log('Page title:', pageTitle);

  const pageContent = await page.content();
  if (pageContent.includes('login') || pageContent.includes('Login') || pageContent.includes('登录')) {
    console.log('WARNING: May need to login');
  }

  // Look for "启动新构建" button
  console.log('Looking for 启动新构建 button...');

  // Try various selectors
  const buttonSelectors = [
    'button:has-text("启动新构建")',
    'button:has-text("新建构建")',
    'button:has-text("Run Pipeline")',
    'button:has-text("触发")',
    '[class*="run"] button',
    'button[class*="primary"]',
  ];

  let triggerButton = null;
  for (const sel of buttonSelectors) {
    try {
      const btn = page.locator(sel).first();
      const visible = await btn.isVisible({ timeout: 3000 });
      if (visible) {
        console.log('Found button with selector:', sel);
        triggerButton = btn;
        break;
      }
    } catch (e) {
      // continue
    }
  }

  if (!triggerButton) {
    // Try text search
    const allButtons = await page.locator('button').all();
    for (const btn of allButtons) {
      const text = await btn.textContent();
      console.log('Button text:', text?.trim());
    }
    await page.screenshot({ path: 'C:\\Users\\yyzypublic\\.openclaw\\workspace\\qa_build_02_no_button.png', fullPage: true });
    throw new Error('Could not find 启动新构建 button');
  }

  // Click the trigger button
  await triggerButton.click();
  console.log('Clicked trigger button');
  await page.waitForTimeout(2000);
  await page.screenshot({ path: 'C:\\Users\\yyzypublic\\.openclaw\\workspace\\qa_build_03_after_click.png', fullPage: false });

  // Now look for the form dialog
  console.log('Looking for form dialog...');

  // Look for dest field
  const destSelectors = [
    'input[placeholder*="dest"]',
    'select[name*="dest"]',
    '[label="dest"] input',
    '[label="dest"] select',
  ];

  // Try to find variable inputs in dialog
  await page.waitForTimeout(1000);

  // Look for any modal/dialog
  const dialogs = await page.locator('[role="dialog"], .modal, .ant-modal, [class*="dialog"]').all();
  console.log('Found dialogs:', dialogs.length);

  // Take screenshot of dialog state
  await page.screenshot({ path: 'C:\\Users\\yyzypublic\\.openclaw\\workspace\\qa_build_04_dialog.png', fullPage: false });

  // Try to find dest input
  // The form might have variable rows with key=dest
  const allInputs = await page.locator('input').all();
  console.log('Total inputs:', allInputs.length);
  for (const inp of allInputs) {
    const val = await inp.getAttribute('value').catch(() => '');
    const placeholder = await inp.getAttribute('placeholder').catch(() => '');
    const name = await inp.getAttribute('name').catch(() => '');
    console.log(`Input: name="${name}" placeholder="${placeholder}" value="${val}"`);
  }

  // Find the dest variable - look for a row containing "dest" text
  const destRow = page.locator('tr, .variable-row, [class*="row"]').filter({ hasText: /^dest$/ }).first();
  const destRowVisible = await destRow.isVisible({ timeout: 3000 }).catch(() => false);

  if (destRowVisible) {
    console.log('Found dest row');
    const destInput = destRow.locator('input, select').first();
    await destInput.click();
    await destInput.fill('1v1_qa');
    console.log('Set dest to 1v1_qa');
  } else {
    // Try to find by label text nearby
    console.log('Trying alternative approach for dest...');

    // Look for all text content to understand form structure  
    const bodyText = await page.locator('body').innerText();
    const lines = bodyText.split('\n').filter(l => l.trim());
    console.log('Page text lines (first 50):');
    lines.slice(0, 50).forEach(l => console.log(' ', l.trim()));
  }

  await page.screenshot({ path: 'C:\\Users\\yyzypublic\\.openclaw\\workspace\\qa_build_05_form.png', fullPage: false });

  await browser.close();
}

run().catch(e => {
  console.error('Error:', e.message);
  process.exit(1);
});

