  const cookiesRaw = readFileSync(cookiesPath, 'utf-8');
  const cookies = JSON.parse(cookiesRaw);
  await context.addCookies(cookies);

  const page = await context.newPage();

  console.log('导航到流水线页面...');
  await page.goto(targetUrl, { waitUntil: 'networkidle', timeout: 30000 });
  console.log('页面标题:', await page.title());

  // 点击"启动新构建"
  console.log('点击 启动新构建...');
  await page.locator('button:has-text("启动新构建")').first().click();
  await page.waitForTimeout(2000);

  // 获取所有 inputs
  // 结构是成对的：第一个 input.value = 变量名（只读），第二个 input.value = 变量值（可编辑）
  // 找到 value="dest" 的 input，然后找它后面紧跟的空 input
  const inputs = await page.locator('input').all();
  console.log('表单中共有 inputs:', inputs.length);

  let destValueInput = null;
  for (let i = 0; i < inputs.length; i++) {
    const val = await inputs[i].inputValue();
    console.log(`  inputs[${i}] value="${val}"`);
    if (val === 'dest' && i + 1 < inputs.length) {
      destValueInput = inputs[i + 1];
      console.log(`  → 找到 dest，值 input 是 inputs[${i + 1}]`);
    }
  }

  if (!destValueInput) {
    throw new Error('找不到 dest 变量对应的输入框！');
  }

  // 填写 dest = 1v1_qa
  await destValueInput.triple_click();  // 全选已有内容
  await destValueInput.fill('1v1_qa');
  const filledVal = await destValueInput.inputValue();
  console.log(`dest 已设置为: "${filledVal}"`);

  await page.screenshot({ path: 'C:\\Users\\yyzypublic\\.openclaw\\workspace\\qa_build_v2_01_filled.png' });

  // 找提交/确定按钮并点击
  console.log('查找提交按钮...');
  const submitSelectors = [
    'button:has-text("确定")',
    'button:has-text("提交")',
    'button:has-text("启动")',
    'button:has-text("运行")',
    'button:has-text("OK")',
    'button:has-text("确认")',
    '.ant-modal-footer button:last-child',
    '[role="dialog"] button[class*="primary"]',
  ];

  let submitBtn = null;
  for (const sel of submitSelectors) {
    try {
