import { chromium } from 'playwright';
import { readFileSync } from 'fs';

const cookiesPath = 'C:\\Users\\yyzypublic\\.openclaw\\workspace\\devops_cookies.json';
const targetUrl = 'https://devops.devcloud.ztgame.com/projects/yyzy/pipelines/p-f78c977835c84b71a6d58b4746cd1c4a';

async function run() {
  const browser = await chromium.launch({ headless: true });
  const context = await browser.newContext();

  const cookiesRaw = readFileSync(cookiesPath, 'utf-8');
  const cookies = JSON.parse(cookiesRaw);
  await context.addCookies(cookies);

  const page = await context.newPage();

  console.log('导航到流水线页面...');
  await page.goto(targetUrl, { waitUntil: 'networkidle', timeout: 30000 });
  console.log('页面标题:', await page.title());

  // 点击"启动新构建"
  console.log('点击 启动新构建...');
  await page.locator('button:has-text("启动新构建")').first().click();
  await page.waitForTimeout(2000);

  // dest 是 ant-design Select 下拉框（role=combobox）
  // 检查当前 dest 的值
  const destSpan = page.locator('.ant-select-selection-item').first();
  const destVisible = await destSpan.isVisible({ timeout: 3000 }).catch(() => false);
  if (destVisible) {
    const currentDestVal = await destSpan.getAttribute('title');
    console.log('当前 dest 值:', currentDestVal);

    if (currentDestVal !== '1v1_qa') {
      // 需要修改 dest 值
      console.log('需要将 dest 改为 1v1_qa...');

      // 点击 dest Select 展开下拉
      const destSelect = page.locator('.ant-select').first();
      await destSelect.click();
      await page.waitForTimeout(1000);

      // 找下拉中的 1v1_qa 选项
      const option = page.locator('.ant-select-item-option').filter({ hasText: '1v1_qa' }).first();
      const optVisible = await option.isVisible({ timeout: 3000 }).catch(() => false);
      if (optVisible) {
        await option.click();
        console.log('已选择 1v1_qa');
      } else {
        // 尝试搜索
        const searchInput = page.locator('input[role="combobox"]').first();
        await searchInput.fill('1v1_qa');
        await page.waitForTimeout(1000);
        const searchOption = page.locator('.ant-select-item-option').filter({ hasText: '1v1_qa' }).first();
        await searchOption.click();
        console.log('搜索并选择 1v1_qa');
      }
    } else {
      console.log('dest 已经是 1v1_qa，无需修改 ✓');
    }
  } else {
    console.log('警告：未找到 dest 的当前值');
  }

  await page.screenshot({ path: 'C:\\Users\\yyzypublic\\.openclaw\\workspace\\qa_build_v3_01_filled.png' });

  // 找提交/确定按钮
  console.log('\n查找提交按钮...');
  const allBtns = await page.locator('button').all();
  console.log('所有按钮:');
  for (const b of allBtns) {
    const t = await b.textContent();
    const v = await b.isVisible().catch(() => false);
    if (v) console.log(`  "${t?.trim()}"`);
  }

  // 优先找 "确定" 按钮（通常在对话框 footer 右边）
  const submitBtn = page.locator('button:has-text("确定")').last();
  const submitVisible = await submitBtn.isVisible({ timeout: 3000 }).catch(() => false);

  if (!submitVisible) {
    // 备用选项
    await page.screenshot({ path: 'C:\\Users\\yyzypublic\\.openclaw\\workspace\\qa_build_v3_02_no_submit.png', fullPage: true });
    throw new Error('找不到确定按钮！');
  }

  // 记录提交前最新构建编号
  const pageTextBefore = await page.locator('body').innerText();
  const buildNumsBefore = pageTextBefore.match(/#(\d+)/g) || [];
  const latestBefore = buildNumsBefore[0];
  console.log('提交前最新构建编号:', latestBefore);

  // 点击提交
  console.log('\n点击确定，触发构建...');
  await submitBtn.click();

  // 等待构建开始
  console.log('等待构建启动...');
  await page.waitForTimeout(4000);

  await page.screenshot({ path: 'C:\\Users\\yyzypublic\\.openclaw\\workspace\\qa_build_v3_03_submitted.png' });

  // 读取提交后页面内容
  const pageTextAfter = await page.locator('body').innerText();
  const lines = pageTextAfter.split('\n').filter(l => l.trim()).slice(0, 40);
  console.log('\n提交后页面内容（前40行）:');
  lines.forEach(l => console.log(' ', l.trim()));

  // 检查是否有运行中状态
  const runningKeywords = ['运行中', '执行中', '进行中', 'Running', '排队'];
  const foundKeyword = runningKeywords.find(kw => pageTextAfter.includes(kw));

  // 检查是否有新的构建编号
  const buildNumsAfter = pageTextAfter.match(/#(\d+)/g) || [];
  const latestAfter = buildNumsAfter[0];
  console.log('\n提交后最新构建编号:', latestAfter);

  const newBuildStarted = latestAfter !== latestBefore;

  if (foundKeyword) {
    console.log(`\n✅ 构建已成功触发！状态关键词: "${foundKeyword}"`);
  } else if (newBuildStarted) {
    console.log(`\n✅ 构建已成功触发！新构建编号: ${latestAfter}`);
  } else {
    console.log('\n⚠️ 无法确认构建状态，请查看截图');
    await browser.close();
    process.exit(2);
  }

  await browser.close();
}

run().catch(e => {
  console.error('Error:', e.message);
  process.exit(1);
});

